module RefModule(
    input [3:0] A,
    input [3:0] B,
    output [3:0] add,
    output [3:0] sub,
    output [3:0] mul,
    output [3:0] div
);// 4-bit adder
      wire _n01 = A[0] ^ B[0];
  wire _c01 = A[0] & B[0];
  wire _n02 = A[1] ^ B[1] ^ _c01;
  wire _c02 = (A[1] & B[1]) | (A[1] & _c01) | (B[1] & _c01);
  wire _n03 = A[2] ^ B[2] ^ _c02;
  wire _c03 = (A[2] & B[2]) | (A[2] & _c02) | (B[2] & _c02);
  wire _n04 = A[3] ^ B[3] ^ _c03;
  wire _c04 = (A[3] & B[3]) | (A[3] & _c03) | (B[3] & _c03);
  assign add = {_n01, _n02, _n03, _n04};

    // 4-bit subtractor
    assign sub = A - B;

    // 4-bit multiplier
    assign mul = A * B;

    // 4-bit divider
    assign div = A / B;

endmodule
